import "sort"

func JobScheduling(arr []int) int {
	n := arr[0]
	type Job struct{ deadline, profit int }
	jobs := make([]Job, n)
	maxDeadline := 0
	for i := 0; i < n; i++ {
		jobs[i] = Job{arr[1+2*i], arr[1+2*i+1]}
		if jobs[i].deadline > maxDeadline {
			maxDeadline = jobs[i].deadline
		}
	}

	sort.Slice(jobs, func(i, j int) bool {
		return jobs[i].profit > jobs[j].profit
	})

	slots := make([]bool, maxDeadline+1)
	totalProfit := 0

	for _, job := range jobs {
		t := job.deadline
		if t > maxDeadline {
			t = maxDeadline
		}
		for ; t > 0; t-- {
			if !slots[t] {
				slots[t] = true
				totalProfit += job.profit
				break
			}
		}
	}

	return totalProfit
}

import java.util.Arrays;

public class JobScheduling {

    public static int jobScheduling(int[] arr) {
        int n = arr[0];
        int[][] jobs = new int[n][2];
        int maxDeadline = 0;
        for (int i = 0; i < n; i++) {
            jobs[i][0] = arr[1 + 2 * i];     // deadline
            jobs[i][1] = arr[1 + 2 * i + 1]; // profit
            maxDeadline = Math.max(maxDeadline, jobs[i][0]);
        }

        Arrays.sort(jobs, (a, b) -> b[1] - a[1]);

        boolean[] slots = new boolean[maxDeadline + 1];
        int totalProfit = 0;

        for (int[] job : jobs) {
            for (int t = Math.min(job[0], maxDeadline); t > 0; t--) {
                if (!slots[t]) {
                    slots[t] = true;
                    totalProfit += job[1];
                    break;
                }
            }
        }

        return totalProfit;
    }
}

fun jobScheduling(arr: IntArray): Int {
    val n = arr[0]
    data class Job(val deadline: Int, val profit: Int)

    val jobs = Array(n) { Job(arr[1 + 2 * it], arr[1 + 2 * it + 1]) }
    val maxDeadline = jobs.maxOf { it.deadline }

    val sorted = jobs.sortedByDescending { it.profit }
    val slots = BooleanArray(maxDeadline + 1)
    var totalProfit = 0

    for (job in sorted) {
        for (t in minOf(job.deadline, maxDeadline) downTo 1) {
            if (!slots[t]) {
                slots[t] = true
                totalProfit += job.profit
                break
            }
        }
    }

    return totalProfit
}

pub fn job_scheduling(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let mut jobs: Vec<(i32, i32)> = (0..n)
        .map(|i| (arr[1 + 2 * i], arr[1 + 2 * i + 1]))
        .collect();

    let max_deadline = jobs.iter().map(|j| j.0).max().unwrap_or(0) as usize;

    jobs.sort_by(|a, b| b.1.cmp(&a.1));

    let mut slots = vec![false; max_deadline + 1];
    let mut total_profit = 0;

    for (deadline, profit) in &jobs {
        let d = (*deadline as usize).min(max_deadline);
        for t in (1..=d).rev() {
            if !slots[t] {
                slots[t] = true;
                total_profit += profit;
                break;
            }
        }
    }

    total_profit
}

object JobScheduling {

  def jobScheduling(arr: Array[Int]): Int = {
    val n = arr(0)
    val jobs = Array.tabulate(n)(i => (arr(1 + 2 * i), arr(1 + 2 * i + 1)))
    val maxDeadline = jobs.map(_._1).max

    val sorted = jobs.sortBy(-_._2)
    val slots = Array.fill(maxDeadline + 1)(false)
    var totalProfit = 0

    for ((deadline, profit) <- sorted) {
      var t = math.min(deadline, maxDeadline)
      var placed = false
      while (t > 0 && !placed) {
        if (!slots(t)) {
          slots(t) = true
          totalProfit += profit
          placed = true
        }
        t -= 1
      }
    }

    totalProfit
  }
}

func jobScheduling(_ arr: [Int]) -> Int {
    let n = arr[0]
    var jobs: [(deadline: Int, profit: Int)] = []
    var maxDeadline = 0

    for i in 0..<n {
        let d = arr[1 + 2 * i]
        let p = arr[1 + 2 * i + 1]
        jobs.append((d, p))
        maxDeadline = max(maxDeadline, d)
    }

    jobs.sort { $0.profit > $1.profit }

    var slots = [Bool](repeating: false, count: maxDeadline + 1)
    var totalProfit = 0

    for job in jobs {
        for t in stride(from: min(job.deadline, maxDeadline), through: 1, by: -1) {
            if !slots[t] {
                slots[t] = true
                totalProfit += job.profit
                break
            }
        }
    }

    return totalProfit
}

export function jobScheduling(arr: number[]): number {
    const n = arr[0];
    const jobs: [number, number][] = [];
    let maxDeadline = 0;

    for (let i = 0; i < n; i++) {
        const deadline = arr[1 + 2 * i];
        const profit = arr[1 + 2 * i + 1];
        jobs.push([deadline, profit]);
        maxDeadline = Math.max(maxDeadline, deadline);
    }

    jobs.sort((a, b) => b[1] - a[1]);

    const slots = new Array(maxDeadline + 1).fill(false);
    let totalProfit = 0;

    for (const [deadline, profit] of jobs) {
        for (let t = Math.min(deadline, maxDeadline); t > 0; t--) {
            if (!slots[t]) {
                slots[t] = true;
                totalProfit += profit;
                break;
            }
        }
    }

    return totalProfit;
}
